class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.size();
        vector<vector<int>> dp(n + 1, vector<int>(k + 1, INT_MAX));
        dp[0][0] = 0;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= min(i, k); j++) {
                for (int d = 1; d < i; d++) {
                    if (i % d == 0) {
                        int changes = 0;
                        for (int group = 0; group < d; group++) {
                            vector<int> count(26, 0);
                            for (int pos = group; pos < i; pos += d) {
                                count[s[pos] - 'a']++;
                            }
                            int maxCount = 0;
                            for (int c = 0; c < 26; c++) {
                                maxCount = max(maxCount, count[c]);
                            }
                            changes += (i / d) - maxCount;
                        }
                        dp[i][j] = min(dp[i][j], dp[i - d][j - 1] + changes);
                    }
                }
            }
        }

        return dp[n][k];
    }
};

